Bash(cd "C:/Users/domen/Desktop/Segon DAW/PROJECTE 2/Ecommerce-Bambes/backend" && php -r "
\\$pdo = new PDO\('sqlite:database/database.sqlite'\);
\\$out = fopen\('database/backup_20260312.sql', 'w'\);

\\$tables = \\$pdo->query\(\\"SELECT name FROM sqlite_master WHERE type='table' AND name != 'sqlite_sequence' ORDER BY name\\"\)->fetchAll\(PDO::FETCH_COLUMN\);

foreach\(\\$tables as \\$table\) {
    // Schema
    \\$schema = \\$pdo->query\(\\"SELECT sql FROM sqlite_master WHERE type='table' AND name='\\$table'\\"\)->fetchColumn\(\);
    fwrite\(\\$out, \\"-- Table: \\$table\\n\\$schema;\\n\\n\\"\);

    // Data
    \\$rows = \\$pdo->query\(\\"SELECT * FROM \\\\\\"\\$table\\\\\\"\\"\)->fetchAll\(PDO::FETCH_ASSOC\);
    if \(!empty\(\\$rows\)\) {
        \\$cols = implode\(', ', array_map\(fn\(\\$c\) => \\"\\\\\\"{\\$c}\\\\\\"\\", array_keys\(\\$rows[0]\)\)\);
        foreach\(\\$rows as \\$row\) {
            \\$vals = implode\(', ', array_map\(fn\(\\$v\) => \\$v === null ? 'NULL' : \\$pdo->quote\(\(string\)\\$v\), array_values\(\\$row\)\)\);
            fwrite\(\\$out, \\"INSERT INTO \\\\\\"\\$table\\\\\\" \(\\$cols\) VALUES \(\\$vals\);\\n\\"\);
        }
        fwrite\(\\$out, \\"\\n\\"\);
    }
}
fclose\(\\$out\);
echo 'Done: backup_20260312.sql\\n';
")

